// Extract data from body - Laravel sends text already extracted
const body = $input.first().json.body || $input.first().json;

const companySlug = body.company_slug || 'default';
const filename = body.filename || 'document.pdf';
const category = body.category || 'general';
const text = body.text || '';
const openaiApiKey = body.openai_api_key || '';
const qdrantApiKey = body.qdrant_api_key || '';
const qdrantHost = body.qdrant_host || '{{QDRANT_URL}}';

// Validate text
if (!text || text.length < 50) {
  throw new Error('No text provided or text too short');
}

// Create collection name
const collectionName = 'company_' + companySlug.replace(/[^a-z0-9_-]/gi, '_').toLowerCase() + '_knowledge';

return {
  json: {
    company_slug: companySlug,
    filename: filename,
    category: category,
    collection_name: collectionName,
    text: text,
    text_length: text.length,
    openai_api_key: openaiApiKey,
    qdrant_host: qdrantHost,
    qdrant_api_key: qdrantApiKey || '',
  }
};

// FIXED: Chunking por longitud forzada - NO depende de \n\n
const input = $input.first().json;
const text = input.text || '';
const companySlug = input.company_slug;
const filename = input.filename;
const category = input.category;
const collectionName = input.collection_name;
const openaiApiKey = input.openai_api_key;
const qdrantHost = input.qdrant_host;

const maxCharsPerChunk = 5000;
const chunks = [];

if (text.length <= maxCharsPerChunk) {
  chunks.push(text);
} else {
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= maxCharsPerChunk) {
      chunks.push(remaining);
      break;
    }
    let cutPoint = maxCharsPerChunk;
    const searchStart = Math.max(0, maxCharsPerChunk - 500);
    const searchZone = remaining.substring(searchStart, maxCharsPerChunk);
    const lastPeriod = searchZone.lastIndexOf('. ');
    const lastNewline = searchZone.lastIndexOf('\n');
    const lastSpace = searchZone.lastIndexOf(' ');
    if (lastPeriod > 0) {
      cutPoint = searchStart + lastPeriod + 1;
    } else if (lastNewline > 0) {
      cutPoint = searchStart + lastNewline + 1;
    } else if (lastSpace > 0) {
      cutPoint = searchStart + lastSpace + 1;
    }
    chunks.push(remaining.substring(0, cutPoint).trim());
    remaining = remaining.substring(cutPoint).trim();
  }
}

console.log('CHUNKING: ' + text.length + ' chars -> ' + chunks.length + ' chunks');

return chunks.map((chunk, index) => ({
  json: {
    text: chunk,
    chunk_index: index,
    total_chunks: chunks.length,
    company_slug: companySlug,
    filename: filename,
    category: category,
    collection_name: collectionName,
    openai_api_key: openaiApiKey,
    qdrant_host: qdrantHost,
    qdrant_api_key: qdrantApiKey || '',
  }
}));

// Process ALL items and prepare data for Qdrant AND Laravel notification
const results = [];
const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const embedding = item.json.data[0].embedding;
  const prevData = $('Split into Chunks').all()[i].json;

  // Generate UUID v4 for Qdrant (required format)
  const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });

  results.push({
    json: {
      id: uuid,
      vector: embedding,
      payload: {
        text: prevData.text,
        filename: prevData.filename,
        category: prevData.category,
        company_slug: prevData.company_slug,
        chunk_index: prevData.chunk_index,
        total_chunks: prevData.total_chunks
      },
      collection_name: prevData.collection_name,
      qdrant_host: prevData.qdrant_host,
    qdrant_api_key: prevData.qdrant_api_key || '',
      // Add these for easy access in Notify Laravel
      company_slug: prevData.company_slug,
      filename: prevData.filename,
      chunk_index: prevData.chunk_index,
      total_chunks: prevData.total_chunks
    }
  });
}

return results;

